int find_i_max(const vector<ll>& nums, ll X) {
    // std::upper_bound returns an iterator to the first element > X
    auto it = upper_bound(nums.begin(), nums.end(), X);
    // The element before this is the last one <= X
    if (it == nums.begin()) {
        return -1;
    }
    // Calculate the 0-based index
    return distance(nums.begin(), it) - 1;
