    if (l_bound > r_bound) return 0;

    // Find iterator to the first element >= l_bound
    auto it_start = lower_bound(E.begin(), E.end(), l_bound);

    // Find iterator to the first element > r_bound
    auto it_end = upper_bound(E.begin(), E.end(), r_bound);

