    // A safe upper bound is 3 * 10^9 + 2.
    const ll MAX_X = 3000000002LL; 

    for (const auto& query : queries) {
        ll l = query[0];
        ll r = query[1];
        ll k = query[2];

        // Binary search for the smallest even number X such that X/2 - C(X) >= k
        ll low = 2;
        ll high = MAX_X;
        ll ans_X = MAX_X;

