// Assuming Int64 corresponds to a 64-bit integer type.
// We need functions for array manipulation and binary search.

#include <stdlib.h>
#include <limits.h>

typedef long long Int64;

/**
 * Finds the index of the first element strictly greater than target in a sorted array.
 * Returns the size of the array if all elements are <= target.
 * This is equivalent to std::upper_bound behavior.
 * @param nums The sorted array.
 * @param n The size of the array.
 * @param target The value to search for.
 * @return The insertion point index (0 to n).
 */
int find_upper_bound_index(const Int64* nums, int n, Int64 target) {
    int low = 0;
    int high = n; // Search space is [0, n]
    int result_index = n;

    while (low < high) {
        int mid = low + (high - low) / 2;
        if (nums[mid] > target) {
            result_index = mid;
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return result_index;
}


/**
 * Solves the problem based on the provided constraints and signature.
 * @param nums The strictly increasing array (Int64).
 * @param queries The queries array (Array<Array<Int64>>).
 * @return The resulting array of answers (Array<Int64>).
 */
Array<Int64> solve(Array<Int64> nums, Array<Array<Int64>> queries) {
    int N = nums.size();
    int Q = queries.size();
    Array<Int64> ans(Q);

    // 1. Preprocessing: Calculate prefix sums for even numbers
    // P[i] stores the count of even numbers in nums[0...i-1]
    int* P = (int*)malloc((N + 1) * sizeof(int));
    P[0] = 0;
    for (int i = 0; i < N; ++i) {
        P[i + 1] = P[i];
        if (nums[i] % 2 == 0) {
            P[i + 1]++;
        }
    }

    // Helper to calculate R(M): count of removed evens <= M in nums[l..r]
    // M is the candidate answer (must be even)
    auto calculate_R = [&](Int64 M, int l, int r) -> int {
        // Find j_M: index of the largest element <= M
        // find_upper_bound_index returns the index of the first element > M.
        int idx_gt_M = find_upper_bound_index(nums.data(), N, M);

        // The largest index i such that nums[i] <= M is idx_gt_M - 1.
        int j_M = idx_gt_M - 1;

        // We are interested in the intersection of [l, r] and [0, j_M]
        int r_prime = (r < j_M) ? r : j_M;

        if (r_prime < l) {
            return 0;
        }

        // Count of evens in nums[l...r_prime]
        // P[r_prime + 1] is count up to r_prime
        // P[l] is count up to l-1
        return P[r_prime + 1] - P[l];
    };

    // 2. Process Queries
    for (int i = 0; i < Q; ++i) {
        Int64 l = queries[i][0];
        Int64 r = queries[i][1];
        Int64 k = queries[i][2];

        // Binary Search for the smallest even A such that C(A) - R(A) >= k

        // L starts at the smallest possible positive even number
        Int64 L = 2;
        // R: Max possible answer. k <= 10^9. Max removed evens <= N=10^5.
        // A/2 approx k + N. A approx 2k + 2N. 
        // Use a generous safe upper bound based on k_max and N_max.
        Int64 R = 2LL * 1000000000LL + 2LL * 100000 + 100; // ~2.0002 * 10^9

        Int64 best_A = -1;

        while (L <= R) {
            // We search over all integers M, but the result A must be even.
            // If we find a suitable M, the answer is M if M is even, or M+1/M-1 otherwise.
            // Since the function f(A) = C(A) - R(A) only increases significantly at even numbers, 
            // searching on even numbers simplifies things, but searching on all integers is safer
            // if we handle the final adjustment.

            Int64 M = L + (R - L) / 2;

            // C(M) = floor(M / 2)
            Int64 C_M = M / 2;

            // R(M) = count of removed evens <= M
            int R_M = calculate_R(M, (int)l, (int)r);

            // Count of remaining evens <= M
            Int64 C_rem = C_M - R_M;

            if (C_rem >= k) {
                // M might be the answer, or the answer is smaller.
                best_A = M;
                R = M - 1;
            } else {
                // M is too small.
                L = M + 1;
            }
        }

        // best_A is the smallest integer M such that C_rem(M) >= k.
        // The answer must be the smallest EVEN number A such that C_rem(A) >= k.

        if (best_A == -1) {
            // Should theoretically not happen given k >= 1 and R is large enough
            // If it did, it means k is too large for the universe we checked.
            ans[i] = -1; // Error indicator
        } else {
            // If best_A is even, it is the answer.
            if (best_A % 2 == 0) {
                ans[i] = best_A;
            } else {
                // If best_A is odd, C_rem(best_A) = C_rem(best_A - 1).
                // The smallest even number A such that C_rem(A) >= k must be best_A + 1 
                // IF C_rem(best_A + 1) > C_rem(best_A) (which is impossible since R is constant between evens).

                // Wait, since C_rem(M) = M/2 - R(M):
                // If M is odd, C_rem(M) = (M-1)/2 - R(M).
                // C_rem(M+1) = (M+1)/2 - R(M+1).

                // If best_A is the smallest M such that C_rem(M) >= k:
                // If best_A is odd, then C_rem(best_A - 1) < k.
                // Since R(best_A) = R(best_A - 1) = R(best_A + 1) = ... (if best_A is not an even removed number),
                // C_rem(best_A - 1) = C_rem(best_A). This contradicts best_A being the smallest M.

                // The only way best_A is odd and minimal is if C_rem(best_A) > C_rem(best_A - 1).
                // This requires best_A/2 > (best_A - 1)/2, which is always true.
                // However, the answer MUST be even. We need the smallest EVEN A >= best_A.

                // If best_A is odd, A = best_A + 1.
                ans[i] = best_A + 1;
            }
        }
    }

    free(P);
    return ans;
}
